    if let EconomyScope::AllProjects(ref projects) = scope {
        let reader = MultiProjectReader::new();
        let per_project = reader.fan_out(projects, |root, proj| {
            per_phase_token_summary(root, EconomyScope::Project(proj.clone()))
        });

function <Name>(s: string) {
  setExpanded((prev) => {
    const next = new Set(prev);
    if (next.has(s)) next.delete(s);
    else next.add(s);
    return next;
  });
}

function <Name>Group(key: GroupKey) {
  setGroupsTouched(true);
  setExpandedGroups((prev) => {
    const next = new Set(prev);
    if (next.has(key)) next.delete(key);
    else next.add(key);
    return next;
  });
}

pub fn <Name>(claude_root: &Path, query: &str, scope: Option<&Scope>, max: usize) -> Vec<Knowledge> {
    <Name>_scored(claude_root, query, scope, max)
        .into_iter()
        .map(|(_, k)| k)
        .collect()
}

/// Like [`<Name>`], but each survivor is paired with its raw BM25 score
/// (×1024 fixed-point — the same byte-stable integer the threshold cut on).

pub struct RecallOpts {
    /// The relevance query (role + task text, free-form).
    pub query: String,
    /// Optional scope filter, pre-parsed from the `--scope` string.
    pub scope: Option<Scope>,
    /// Optional `.claude/` root override. `None` ⇒ resolve from the cwd.
    pub root: Option<PathBuf>,
    /// Result cap.
    pub max: usize,

    fn <name>(self) -> &'static str {
        match self {
            Self::BuildRed => "build_red",
            Self::AcFailing => "ac_failing",
        }
    }
}

